script:
function __excelCtx(ctx){
  function doc(){ return ctx && ctx.$el ? ctx.$el.ownerDocument : document; }
  function visible(el){ if(!el) return false; var w=doc().defaultView||window; var s=w.getComputedStyle(el), r=el.getBoundingClientRect(); return s.display!=='none' && s.visibility!=='hidden' && r.width>0 && r.height>0; }
  function inputs(){ return Array.prototype.slice.call(doc().querySelectorAll('input,textarea')).filter(visible).filter(function(el){ return el.getBoundingClientRect().y < 230; }); }
  function inputValue(kind, fallback){ var list=inputs(); var el=null; if(kind==='addr') el=list.find(function(i){ return /cell address/i.test(i.placeholder||''); }) || list[0]; if(kind==='value') el=list.find(function(i){ return /value to write/i.test(i.placeholder||''); }) || list[1]; var v=el ? el.value : ''; if(v===undefined || v===null || v==='') return fallback; return String(v).trim(); }
  function report(){ var d=doc(); return d.querySelector('.page_report_view_container') && d.querySelector('.page_report_view_container').__vue__; }
  function sheetView(){ var d=doc(); return d.querySelector('.report-view-main') && d.querySelector('.report-view-main').__vue__; }
  function sheet(){ var vm=sheetView(); if(!vm || !vm.univerAPI) throw new Error('univerAPI not found'); return vm.univerAPI.getActiveWorkbook().getActiveSheet(); }
  function log(msg, detail){ var sh=sheet(); var r=sh.getRange('J1'); r.setValue((new Date()).toLocaleTimeString() + ' ' + msg); try { r.setBackground('#fff7ed'); r.setFontColor('#9a3412'); r.setFontWeight('bold'); } catch(e) {} if(detail!==undefined){ var d=sh.getRange('J2'); d.setValue(String(detail)); try { d.setBackground('#f8fafc'); d.setFontColor('#111827'); } catch(e2) {} } window.__wos4ExcelLastAction={message:msg, detail:detail, at:new Date().toISOString()}; }
  function sampleImageUrl(){ var svg='<svg xmlns="http://www.w3.org/2000/svg" width="220" height="110" viewBox="0 0 220 110"><defs><linearGradient id="g" x1="0" y1="0" x2="1" y2="1"><stop stop-color="#16a34a"/><stop offset="1" stop-color="#0f766e"/></linearGradient></defs><rect width="220" height="110" rx="14" fill="url(#g)"/><rect x="16" y="18" width="188" height="74" rx="8" fill="#ecfdf5"/><g stroke="#86efac" stroke-width="1"><path d="M16 40h188M16 62h188M16 84h188M58 18v74M100 18v74M142 18v74M184 18v74"/></g><path d="M28 78L66 55l34 13 34-32 52 20" fill="none" stroke="#2563eb" stroke-width="5" stroke-linecap="round" stroke-linejoin="round"/><circle cx="66" cy="55" r="5" fill="#f97316"/><circle cx="134" cy="36" r="5" fill="#f97316"/><text x="110" y="104" text-anchor="middle" font-family="Arial" font-size="10" fill="#ffffff">WOS4 Excel Report</text></svg>'; return 'data:image/svg+xml;charset=utf-8,'+encodeURIComponent(svg); }
  function normalizeAddress(addr){ addr=String(addr||'B1').trim().toUpperCase(); return /^[A-Z]+[1-9][0-9]*$/.test(addr) ? addr : 'B1'; }
  return {doc:doc, report:report, sheetView:sheetView, sheet:sheet, log:log, inputValue:inputValue, normalizeAddress:normalizeAddress, sampleImageUrl:sampleImageUrl};
}

try {
  var x=__excelCtx(this), rv=x.report();
  if (!rv || !rv.Print) throw new Error('Report Print not found');
  function setBreaks(rv, sh){ var sid=sh.getSheetId(); var pb={}; pb[sid]={h:[44,89,134],v:[]}; if(rv && rv.$store && rv.storeName) rv.$store.dispatch(rv.storeName.viewStore + '/updaterReportData', {key:'pageBreakList', value:pb}); try { rv.reportData.pageBreakList=pb; } catch(e) {} return pb; }
  function seedRows(){
    var sh=x.sheet();
    try { sh.getRange('A1:H1').breakApart(); } catch(ba1) {}
    try { sh.getRange('A163:H163').breakApart(); } catch(ba2) {}
    try { sh.setRowCount(180); sh.setColumnCount(12); } catch(e) {}
    try { sh.getRange('A1:L180').clear(); } catch(e1) { try { sh.getRange('A1:L180').clearContent(); } catch(e2) {} }
    var rows=[];
    rows.push(['WOS4 Excel print experiment '+(new Date()).toLocaleString(),'','','','','','','']);
    rows.push(['No','Batch','Item','Group','Qty','Score','Owner','Remark']);
    for (var i=1;i<=160;i++) rows.push([i,'BATCH-'+(Math.ceil(i/20)),'ITEM-'+('000'+i).slice(-3),'G'+((i%5)+1),20+(i%80),60+(i%40),'tester-'+((i%7)+1),'page data row '+i]);
    rows.push(['PRINT FOOTER DECORATION - generated by WOS4 Excel experiment','','','','','','','']);
    sh.getRange('A1:H163').setValues(rows);
    try { sh.getRange('A1:H1').merge(); sh.getRange('A163:H163').merge(); } catch(e3) {}
    sh.getRange('A1:H1').setBackground('#1d4ed8').setFontColor('#ffffff').setFontWeight('bold').setFontSize(14);
    sh.getRange('A2:H2').setBackground('#0f172a').setFontColor('#ffffff').setFontWeight('bold');
    sh.getRange('A163:H163').setBackground('#dbeafe').setFontColor('#1e3a8a').setFontWeight('bold');
    return {sh:sh, rows:rows};
  }
  function fallbackPrint(rows){
    var d=x.doc();
    var imgUrl=window.__wos4ExcelPrintImageUrl || window.__wos4ExcelImageUrl || x.sampleImageUrl();
    function esc(v){ return String(v==null?'':v).replace(/[&<>]/g,function(c){ return {'&':'&amp;','<':'&lt;','>':'&gt;'}[c]; }); }
    var old=d.getElementById('wos4_excel_print_fallback_frame'); if(old) old.remove();
    var title='<tr><th colspan="8"><div class="title-wrap"><span>'+esc(rows[0][0])+'</span><img class="title-img" src="'+imgUrl+'"></div></th></tr>';
    var head='<tr>'+rows[1].map(function(v,idx){ var text=esc(v); if(idx===7) text=text+'<br><img class="cell-img" src="'+imgUrl+'">'; return '<th>'+text+'</th>'; }).join('')+'</tr>';
    var foot='<tr><td colspan="8">'+esc(rows[162][0])+'</td></tr>';
    var body='';
    for(var i=2;i<162;i++){
      body+='<tr>'+rows[i].map(function(v,idx){ var text=esc(v); if(i===4 && idx===7) text='<img class="body-img" src="'+imgUrl+'"><div>'+text+'</div>'; return '<td>'+text+'</td>'; }).join('')+'</tr>';
    }
    var html='<!doctype html><html><head><meta charset="utf-8"><title>WOS4 Excel Print</title><style>@page{size:A4;margin:12mm;}body{font-family:Arial,"Microsoft YaHei",sans-serif;margin:0;color:#111827;}table{border-collapse:collapse;width:100%;font-size:10px;}th,td{border:1px solid #d1d5db;padding:4px 5px;vertical-align:middle;}thead{display:table-header-group;}tfoot{display:table-footer-group;}thead tr:first-child th{background:#1d4ed8;color:white;font-size:14px;text-align:left;}thead tr:nth-child(2) th{background:#0f172a;color:white;}tfoot td{background:#dbeafe;color:#1e3a8a;font-weight:bold;text-align:center;}.title-wrap{display:flex;align-items:center;justify-content:space-between;gap:10px}.title-img{width:96px;height:auto;border-radius:6px;background:white;padding:2px}.cell-img{display:block;width:70px;height:auto;margin:3px auto 0;border-radius:4px;background:white;padding:2px}.body-img{display:block;width:120px;height:auto;margin:0 auto 4px;border-radius:6px}tr{break-inside:avoid;page-break-inside:avoid;}</style></head><body><table><thead>'+title+head+'</thead><tfoot>'+foot+'</tfoot><tbody>'+body+'</tbody></table></body></html>';
    window.__wos4ExcelLastPrintHtml=html;
    window.__wos4ExcelPrintImageIncluded=html.indexOf('<img')>=0;
    var iframe=d.createElement('iframe'); iframe.id='wos4_excel_print_fallback_frame'; iframe.style.position='fixed'; iframe.style.right='0'; iframe.style.bottom='0'; iframe.style.width='1px'; iframe.style.height='1px'; iframe.style.opacity='0'; d.body.appendChild(iframe);
    var idoc=iframe.contentWindow.document; idoc.open(); idoc.write(html); idoc.close();
    window.__wos4ExcelFallbackPrintCount=(window.__wos4ExcelFallbackPrintCount||0)+1;
    setTimeout(function(){ try { iframe.contentWindow.focus(); iframe.contentWindow.print(); x.log('PRINT fallback browser dialog requested with image preserved', 'native Print first, fallback HTML includes img tags'); } catch(e) { x.log('PRINT FALLBACK ERROR '+e.message); } }, 250);
  }
  var seeded=seedRows(), sh=seeded.sh;
  var imgUrl=window.__wos4ExcelPrintImageUrl || window.__wos4ExcelImageUrl || x.sampleImageUrl();
  window.__wos4ExcelImageUrl=imgUrl; window.__wos4ExcelPrintImageUrl=imgUrl;
  setBreaks(rv, sh);
  try { sh.getRange('H2').insertCellImageAsync(imgUrl); } catch(imageCellErr) {}
  var opt={ type:0, size:(rv.reportData && rv.reportData.properties && rv.reportData.properties.paperSize) || 'A4', intOrient:1, preview:false, title:{startRow:0,endRow:0}, header:{startRow:1,endRow:1}, tail:{startRow:162,endRow:162}, isPaging:true, isPageNumber:true, pageStyle:0, pagePosition:1, pageNumberType:1, paddingTop:0, paddingRight:0, paddingBottom:0, paddingLeft:0 };
  window.__wos4ExcelBeforePrintCount = window.__wos4ExcelBeforePrintCount || 0; window.__wos4ExcelAfterPrintCount = window.__wos4ExcelAfterPrintCount || 0; window.__wos4ExcelFallbackPrintCount = 0;
  if (!window.__wos4ExcelPrintEventInstalled) { window.addEventListener('beforeprint', function(){ window.__wos4ExcelBeforePrintCount++; }); window.addEventListener('afterprint', function(){ window.__wos4ExcelAfterPrintCount++; }); window.__wos4ExcelPrintEventInstalled = true; }
  window.__wos4ExcelLastPrintOptions=opt;
  var res=rv.Print(0, {}, opt);
  if (res && res.errorCode) x.log('PRINT native error, fallback pending '+JSON.stringify(res)); else x.log('PRINT native requested; image fallback will open if native print does not start');
  setTimeout(function(){ if(!window.printJS && (window.__wos4ExcelBeforePrintCount||0)===0) fallbackPrint(seeded.rows); }, 1500);
} catch(e) { try { __excelCtx(this).log('PRINT ERROR '+e.message); } catch(_) {} }
